INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('7f9e8367-8ff6-48a7-8b3a-8c343a660862', 'Product Inquiry', 'product-inquiry', 'Ask a question about a product', '[{"name":"name","type":"text","label":"Name","required":true,"placeholder":"Your name","maxLength":100},{"name":"email","type":"email","label":"Email","required":true,"placeholder":"you@example.com"},{"name":"product_type","type":"select","label":"Product Type","required":true,"options":["Physical Product","Digital Product","Service","Other"]},{"name":"message","type":"textarea","label":"Your Question","required":true,"placeholder":"What would you like to know?","maxLength":2000}]', '{"success_message":"Thanks for your inquiry! We''ll get back to you shortly.","require_honeypot":true}', 'active', '2026-03-27T01:23:01.276Z', '2026-03-27T01:23:01.276Z');
INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('6bb75f40-15f0-4904-8323-5566fd68914a', 'Newsletter', 'newsletter', 'Subscribe to product updates and offers', '[{"name":"email","type":"email","label":"Email Address","required":true,"placeholder":"you@example.com"}]', '{"success_message":"You''re subscribed! Watch your inbox for product updates and special offers.","require_honeypot":true}', 'active', '2026-03-27T01:23:01.276Z', '2026-03-27T01:23:01.276Z');
